**KQL offre des opérateurs de chaînes puissants pour analyser les logs :**

```kql
// ─── Opérateurs de chaînes ───
// has          : contient un mot (insensible casse, optimisé index)
// contains     : contient une sous-chaîne (insensible casse)
// startswith   : commence par
// endswith     : se termine par
// matches regex: regex complète
// !has / !contains : négation

Syslog
| where SyslogMessage has "Failed"
| where SyslogMessage !has "pam_unix"

// ─── Sensible à la casse ───
// has_cs, contains_cs, startswith_cs, endswith_cs
Table
| where Column has_cs "ERROR"

// ─── in et !in ───
SecurityEvent
| where EventID in (4624, 4625, 4648)
| where Computer !in ("DC01", "DC02")

// ─── Wildcards ───
SecurityEvent
| where Computer startswith "WORKSTATION"
| where Account endswith "$"  // Comptes machine AD

// ─── extract() : regex avec groupe ───
// extract(regex, groupe, texte)
Syslog
| extend IP = extract(@"from ([0-9.]+)", 1, SyslogMessage)
| extend User = extract(@"for (\S+) from", 1, SyslogMessage)

// ─── parse : parse par template ───
// Plus lisible qu'extract pour des formats fixes
Syslog
| parse SyslogMessage with "Failed password for " Username " from " SourceIP " port " Port " ssh2"
| where isnotempty(SourceIP)
```

**Les jointures permettent de corréler des événements de tables différentes :**

```kql
// ─── join : joindre deux tables ───
// inner join par défaut
let BreachIPs = SecurityAlert
    | where AlertName has "Brute Force"
    | extend IP = tostring(Entities[0].Address)
    | summarize by IP;

SigninLogs
| where TimeGenerated > ago(24h)
| join kind=inner BreachIPs on $left.IPAddress == $right.IP
| project TimeGenerated, UserPrincipalName, IPAddress, Location

// ─── Types de join ───
// inner    : lignes avec correspondance dans les deux tables
// leftouter: toutes les lignes de gauche + correspondances
// antiright: lignes de gauche SANS correspondance (exclusion)

// ─── Exemple antiright (IPs non vues en alerte) ───
SigninLogs
| summarize by IPAddress
| join kind=antiright (
    SecurityAlert | extend IP = tostring(Entities[0].Address) | summarize by IP
) on $left.IPAddress == $right.IP

// ─── union : combiner plusieurs tables ───
let LinuxAuth = Syslog | where Facility == "auth" | extend Source = "Linux";
let WindowsAuth = SecurityEvent | where EventID in (4624, 4625) | extend Source = "Windows";

union LinuxAuth, WindowsAuth
| summarize Count=count() by Source, bin(TimeGenerated, 1h)
| render timechart

// ─── lookup : table de référence ───
let IOCTable = datatable(IP:string, Menace:string)[
    "185.220.101.3", "TOR C2",
    "194.165.16.11", "Scanner"
];
SigninLogs
| lookup kind=inner IOCTable on $left.IPAddress == $right.IP
| project TimeGenerated, UserPrincipalName, IPAddress, Menace
```

**`let` permet de définir des variables et de structurer des requêtes complexes :**

```kql
// ─── let : variable scalaire ───
let SeuillBruteForce = 10;
let FenetreTemps = 1h;

SecurityEvent
| where TimeGenerated > ago(FenetreTemps)
| where EventID == 4625
| summarize Count=count() by IpAddress
| where Count >= SeuillBruteForce

// ─── let : sous-requête (table) ───
let IPSuspectes = SecurityEvent
    | where EventID == 4625
    | where TimeGenerated > ago(24h)
    | summarize Fails=count() by IpAddress
    | where Fails >= 5
    | project IpAddress;

// Utiliser la variable dans la requête principale
SecurityEvent
| where TimeGenerated > ago(24h)
| where EventID == 4624  // Succès
| where IpAddress in (IPSuspectes)  // Filtrer par IPs suspectes
| project TimeGenerated, IpAddress, Account, Computer

// ─── let : fonction ───
let scorer = (activite:string) {
    case(
        activite == "port_scan", 20,
        activite == "brute_force", 40,
        activite == "login_success_after_fail", 80,
        10  // défaut
    )
};

// datatable : créer une table inline ───
let Liste_Noire = datatable(IP:string, Raison:string) [
    "185.220.101.3", "TOR exit node",
    "194.165.16.11", "Known scanner",
    "45.33.32.156",  "Shodan host"
];

SecurityEvent
| where EventID == 4625
| join kind=inner Liste_Noire on $left.IpAddress == $right.IP
| project TimeGenerated, IpAddress, Account, Raison
```
